import React, { useState, useEffect } from 'react';

const StudentManager = () => {
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({ name: '', email: '', grade: '' });
  const [editingId, setEditingId] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    fetchStudents();
  }, []);

  const fetchStudents = async () => {
    setLoading(true);
    try {
      const response = await fetch('http://localhost:5000/students');
      const data = await response.json();
      setStudents(data);
    } catch (error) {
      console.error('Error fetching students:', error);
    }
    setLoading(false);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.name || !formData.email || !formData.grade) {
      alert('All fields required');
      return;
    }

    try {
      if (editingId) {
        const response = await fetch(`http://localhost:5000/students/${editingId}`, {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(formData)
        });
        const updated = await response.json();
        setStudents(students.map(s => s.id === editingId ? updated : s));
      } else {
        const response = await fetch('http://localhost:5000/students', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(formData)
        });
        const newStudent = await response.json();
        setStudents([...students, newStudent]);
      }
      resetForm();
      fetchStudents(); // Refresh
    } catch (error) {
      alert('Save failed');
    }
  };

  const resetForm = () => {
    setShowForm(false);
    setEditingId(null);
    setFormData({ name: '', email: '', grade: '' });
  };

  const handleEdit = (student) => {
    setFormData(student);
    setEditingId(student.id);
    setShowForm(true);
  };

  const handleDelete = async (id) => {
  if (!window.confirm('Delete student?')) return;
    try {
      await fetch(`http://localhost:5000/students/${id}`, { method: 'DELETE' });
      setStudents(students.filter(s => s.id !== id));
    } catch (error) {
      alert('Delete failed');
    }
  };

  const filteredStudents = students.filter(student =>
    student.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const gradeConfig = {
    A: { color: 'emerald', label: 'Excellent' },
    B: { color: 'sky', label: 'Good' },
    C: { color: 'amber', label: 'Average' },
    D: { color: 'orange', label: 'Poor' },
    F: { color: 'red', label: 'Fail' }
  };

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-5xl font-black bg-gradient-to-r from-emerald-400 to-teal-400 bg-clip-text text-transparent">
            👥 Student Database
          </h2>
          <p className="text-xl text-slate-400 mt-2">Manage grades and records</p>
        </div>
        <button
          onClick={() => setShowForm(true)}
          className="btn btn-primary px-8 py-4 text-lg font-black shadow-lg hover:shadow-emerald-500/30"
        >
          + Add Student
        </button>
      </div>

      {/* Search */}
      <div className="glass p-6 rounded-3xl">
        <input
          type="text"
          placeholder="Search students by name or email..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="form-input px-12 py-5 text-lg placeholder-slate-500 focus:ring-emerald-400/30"
        />
      </div>

      {/* Form */}
      {showForm && (
        <div className="glass p-10 rounded-3xl max-w-4xl mx-auto">
          <div className="flex items-center justify-between mb-12">
            <h3 className="text-4xl font-black text-white">
              {editingId ? 'Edit Student' : 'New Student'}
            </h3>
            <button onClick={resetForm} className="btn btn-secondary px-8 py-3 text-lg">
              Cancel
            </button>
          </div>
          
          <form onSubmit={handleSubmit} className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div>
              <label className="form-label">Full Name</label>
              <input
                type="text"
                placeholder="John Doe"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                className="form-input text-xl"
                required
              />
            </div>
            <div>
              <label className="form-label">Email</label>
              <input
                type="email"
                placeholder="john@example.com"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                className="form-input text-xl"
                required
              />
            </div>
            <div>
              <label className="form-label">Grade</label>
              <input
                type="text"
                placeholder="A"
                value={formData.grade}
                maxLength="1"
                onChange={(e) => setFormData({ ...formData, grade: e.target.value.toUpperCase() })}
                className="form-input text-3xl font-black tracking-wider uppercase text-emerald-400"
                required
              />
            </div>
            <div className="lg:col-span-3 flex gap-4 pt-4">
              <button type="submit" className="flex-1 btn btn-primary py-5 text-xl font-black shadow-2xl">
                {editingId ? '💾 Update Student' : '➕ Add Student'}
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Grid */}
      {loading ? (
        <div className="flex items-center justify-center h-96">
          <div className="w-20 h-20 border-4 border-slate-700 border-t-emerald-500 rounded-full animate-spin"></div>
        </div>
      ) : filteredStudents.length === 0 ? (
        <div className="text-center py-32 glass rounded-3xl">
          <div className="text-8xl mb-8">👨‍🎓</div>
          <h3 className="text-4xl font-black mb-4 text-slate-300">No Students</h3>
          <p className="text-xl text-slate-500 max-w-lg mx-auto">Add your first student to get started</p>
        </div>
      ) : (
        <div className="grid-responsive">
          {filteredStudents.map((student, idx) => {
            const grade = gradeConfig[student.grade] || gradeConfig.A;
            return (
              <div key={student.id} className="card p-8 hover:shadow-xl group">
                <div className="flex items-start justify-between mb-6">
                  <div className="flex items-center gap-4">
                    <div className="w-16 h-16 bg-gradient-to-br from-emerald-500/20 to-teal-500/20 rounded-2xl flex items-center justify-center border-2 border-emerald-500/30">
                      <span className="text-2xl">👤</span>
                    </div>
                    <div>
                      <h4 className="text-2xl font-black text-white mb-1">{student.name}</h4>
                      <p className={`text-sm font-semibold px-3 py-1 rounded-full bg-${grade.color}-500/10 border border-${grade.color}-400/30 text-${grade.color}-400`}>
                        {student.grade} - {grade.label}
                      </p>
                    </div>
                  </div>
                  <span className="text-3xl font-black text-slate-400">#{student.id}</span>
                </div>
                
                <p className="text-slate-400 mb-8 text-lg">{student.email}</p>
                
                <div className="flex gap-3 pt-6 border-t border-slate-800/50">
                  <button
                    onClick={() => handleEdit(student)}
                    className="flex-1 btn btn-primary py-3 px-6 text-sm font-black"
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => handleDelete(student.id)}
                    className="flex-1 btn bg-gradient-to-r from-red-500/90 to-red-600/90 hover:from-red-600 hover:to-red-700 border-red-400/40 text-white py-3 px-6 text-sm font-black shadow-lg hover:shadow-red-500/30"
                  >
                    Delete
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default StudentManager;
